let futu = global.get('futuClient');
if (!futu || !futu.connected) {
    global.set('futuNeedConnect', true);
    return { payload: { action: 'connect' } };
}
global.set('futuNeedConnect', false);
return { payload: { action: 'subscribe', symbols: ['MNQ'] } };

const data = msg.payload;

// Handle different message types from Futu OpenD
if (data.type === 'quote' && data.symbol === 'MNQ') {
    const parsed = {
        symbol: 'MNQ',
        price: data.last || data.price,
        open_price: data.open,
        high_price: data.high,
        low_price: data.low,
        volume: data.volume || data.vol,
        turnover: data.turnover,
        open_interest: data.openInterest || data.oi,
        bid_price: data.bid1,
        ask_price: data.ask1,
        bid_volume: data.bidVol1,
        ask_volume: data.askVol1,
        timestamp: new Date(data.time || Date.now()).toISOString(),
        source: 'futu_opend',
        data_type: 'tick',
        metadata: JSON.stringify({
            security_type: data.securityType,
            exchange: data.exchange,
            lot_size: data.lotSize
        })
    };
    return { payload: parsed };
}

return null;

if (msg.payload.error) {
    node.error('Futu OpenD Error: ' + msg.payload.error);
    // Attempt reconnection after error
    setTimeout(() => {
        global.set('futuNeedConnect', true);
    }, 5000);
}
return null;
